//! Database connection management.
//!
//! This module handles opening, creating, and managing SQLite database connections.
//! Key responsibilities:
//! - Open or create database at `.harness/harness.db`
//! - Run pragmas on every connection
//! - Ensure schema is initialized

use std::path::{Path, PathBuf};

use rusqlite::Connection;

use super::schema::{init_schema, is_initialized};
use super::DbResult;

/// Database filename within the `.harness` folder.
pub const DB_FILENAME: &str = "harness.db";

/// Harness folder name.
pub const HARNESS_FOLDER: &str = ".harness";

/// Get the path to the database file for a project.
///
/// Returns `<project_root>/.harness/harness.db`
pub fn get_db_path(project_root: &Path) -> PathBuf {
    project_root.join(HARNESS_FOLDER).join(DB_FILENAME)
}

/// Check if a project has a harness database.
pub fn has_database(project_root: &Path) -> bool {
    get_db_path(project_root).exists()
}

/// Check if a project has a harness folder (may have legacy files or database).
pub fn has_harness_folder(project_root: &Path) -> bool {
    project_root.join(HARNESS_FOLDER).is_dir()
}

/// Open an existing database connection.
///
/// Returns an error if the database doesn't exist or isn't initialized.
pub fn open(project_root: &Path) -> DbResult<Connection> {
    let db_path = get_db_path(project_root);

    if !db_path.exists() {
        return Err(super::DbError::NotFound(format!(
            "Database not found at: {}",
            db_path.display()
        )));
    }

    let conn = Connection::open(&db_path)?;

    // Run pragmas on every connection
    conn.execute_batch(super::schema::PRAGMAS)?;

    if !is_initialized(&conn) {
        return Err(super::DbError::Validation(
            "Database exists but schema not initialized".to_string(),
        ));
    }

    Ok(conn)
}

/// Open or create a database connection.
///
/// If the database doesn't exist, creates it and initializes the schema.
/// If the database exists but schema isn't initialized, initializes it.
pub fn open_or_create(project_root: &Path) -> DbResult<Connection> {
    let db_path = get_db_path(project_root);

    // Ensure .harness folder exists
    let harness_folder = project_root.join(HARNESS_FOLDER);
    if !harness_folder.exists() {
        std::fs::create_dir_all(&harness_folder)?;
    }

    let conn = Connection::open(&db_path)?;

    // Run pragmas on every connection
    conn.execute_batch(super::schema::PRAGMAS)?;

    // Initialize schema if needed
    if !is_initialized(&conn) {
        init_schema(&conn)?;
    }

    Ok(conn)
}

/// Create an in-memory database for testing.
///
/// The database is initialized with the full schema.
pub fn open_in_memory() -> DbResult<Connection> {
    let conn = Connection::open_in_memory()?;
    conn.execute_batch(super::schema::PRAGMAS)?;
    init_schema(&conn)?;
    Ok(conn)
}

/// Get database statistics.
#[derive(Debug, Clone, Default)]
pub struct DbStats {
    /// Total number of tasks.
    pub task_count: u64,
    /// Number of tasks by status.
    pub task_by_status: std::collections::HashMap<String, u64>,
    /// Total number of steps.
    pub step_count: u64,
    /// Total number of sessions.
    pub session_count: u64,
    /// Total number of progress entries.
    pub progress_count: u64,
    /// Database file size in bytes.
    pub file_size_bytes: u64,
}

impl DbStats {
    /// Collect statistics from a database connection.
    pub fn collect(conn: &Connection, db_path: Option<&Path>) -> DbResult<Self> {
        let mut stats = DbStats::default();

        // Count tasks
        stats.task_count = conn.query_row(
            "SELECT COUNT(*) FROM project_tasks",
            [],
            |row| row.get(0),
        )?;

        // Count tasks by status
        let mut stmt = conn.prepare(
