//! - Run pragmas on every connection
//! - Ensure schema is initialized

use std::path::{Path, PathBuf};

use rusqlite::Connection;

use super::schema::{init_schema, is_initialized};
use super::DbResult;

/// Database filename within the `.harness` folder.
pub const DB_FILENAME: &str = "harness.db";

/// Harness folder name.
pub const HARNESS_FOLDER: &str = ".harness";

/// Get the path to the database file for a project.
///
/// Returns `<project_root>/.harness/harness.db`
pub fn get_db_path(project_root: &Path) -> PathBuf {
    project_root.join(HARNESS_FOLDER).join(DB_FILENAME)
}

/// Check if a project has a harness database.
pub fn has_database(project_root: &Path) -> bool {
    get_db_path(project_root).exists()
}

/// Check if a project has a harness folder (may have legacy files or database).
pub fn has_harness_folder(project_root: &Path) -> bool {
    project_root.join(HARNESS_FOLDER).is_dir()
}

/// Open an existing database connection.
///
/// Returns an error if the database doesn't exist or isn't initialized.
pub fn open(project_root: &Path) -> DbResult<Connection> {
    let db_path = get_db_path(project_root);

    if !db_path.exists() {
        return Err(super::DbError::NotFound(format!(
            "Database not found at: {}",
            db_path.display()
        )));
    }

    let conn = Connection::open(&db_path)?;

    // Run pragmas on every connection
    conn.execute_batch(super::schema::PRAGMAS)?;

    if !is_initialized(&conn) {
        return Err(super::DbError::Validation(
            "Database exists but schema not initialized".to_string(),
        ));
    }

    Ok(conn)
}

/// Open or create a database connection.
///
/// If the database doesn't exist, creates it and initializes the schema.
/// If the database exists but schema isn't initialized, initializes it.
pub fn open_or_create(project_root: &Path) -> DbResult<Connection> {
    let db_path = get_db_path(project_root);

    // Ensure .harness folder exists
    let harness_folder = project_root.join(HARNESS_FOLDER);
    if !harness_folder.exists() {
        std::fs::create_dir_all(&harness_folder)?;
    }

    let conn = Connection::open(&db_path)?;

    // Run pragmas on every connection
    conn.execute_batch(super::schema::PRAGMAS)?;

    // Initialize schema if needed
    if !is_initialized(&conn) {
        init_schema(&conn)?;
    }

    Ok(conn)
}

/// Create an in-memory database for testing.
///
/// The database is initialized with the full schema.
pub fn open_in_memory() -> DbResult<Connection> {
    let conn = Connection::open_in_memory()?;
    conn.execute_batch(super::schema::PRAGMAS)?;
    init_schema(&conn)?;
    Ok(conn)
}

/// Get database statistics.
#[derive(Debug, Clone, Default)]
pub struct DbStats {
    /// Total number of tasks.
    pub task_count: i64,
    /// Number of tasks by status.
    pub task_by_status: std::collections::HashMap<String, i64>,
    /// Total number of steps.
    pub step_count: i64,
    /// Total number of sessions.
    pub session_count: i64,
    /// Total number of progress entries.
    pub progress_count: i64,
    /// Database file size in bytes.
    pub file_size_bytes: u64,
}

impl DbStats {
    /// Collect statistics from a database connection.
    pub fn collect(conn: &Connection, db_path: Option<&Path>) -> DbResult<Self> {
        let mut stats = DbStats::default();

        // Count tasks
        stats.task_count = conn.query_row(
            "SELECT COUNT(*) FROM project_tasks",
            [],
            |row| row.get(0),
        )?;

        // Count tasks by status
        let mut stmt = conn.prepare(
            "SELECT status, COUNT(*) FROM project_tasks GROUP BY status",
        )?;
        let rows = stmt.query_map([], |row| {
            Ok((row.get::<_, String>(0)?, row.get::<_, i64>(1)?))
        })?;
        for row in rows {
            let (status, count) = row?;
            stats.task_by_status.insert(status, count);
        }

        // Count steps
        stats.step_count = conn.query_row(
            "SELECT COUNT(*) FROM task_steps",
            [],
            |row| row.get(0),
        )?;

        // Count sessions
        stats.session_count = conn.query_row(
            "SELECT COUNT(*) FROM work_sessions",
            [],
            |row| row.get(0),
        )?;

        // Count progress
        stats.progress_count = conn.query_row(
            "SELECT COUNT(*) FROM project_progress",
            [],
            |row| row.get(0),
        )?;

        // Get file size if path provided
        if let Some(path) = db_path {
            if let Ok(metadata) = std::fs::metadata(path) {
                stats.file_size_bytes = metadata.len();
            }
        }

        Ok(stats)
    }
}

// =============================================================================
// TESTS
// =============================================================================

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    fn create_temp_project() -> TempDir {
        TempDir::new().expect("Failed to create temp directory")
    }

    // -------------------------------------------------------------------------
    // Path tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_get_db_path() {
        let project_root = Path::new("/home/user/project");
        let db_path = get_db_path(project_root);
        assert_eq!(db_path, PathBuf::from("/home/user/project/.harness/harness.db"));
    }

    #[test]
    fn test_has_database_false_when_missing() {
        let temp = create_temp_project();
        assert!(!has_database(temp.path()));
    }

    #[test]
    fn test_has_harness_folder_false_when_missing() {
        let temp = create_temp_project();
        assert!(!has_harness_folder(temp.path()));
    }

    #[test]
    fn test_has_harness_folder_true_when_exists() {
        let temp = create_temp_project();
        std::fs::create_dir(temp.path().join(".harness")).expect("Failed to create .harness");
        assert!(has_harness_folder(temp.path()));
    }

    // -------------------------------------------------------------------------
    // Open tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_open_fails_when_db_missing() {
        let temp = create_temp_project();
        let result = open(temp.path());
        assert!(result.is_err());
        assert!(matches!(result.unwrap_err(), super::super::DbError::NotFound(_)));
    }

    #[test]
    fn test_open_or_create_creates_db() {
        let temp = create_temp_project();

        // Database should not exist yet
        assert!(!has_database(temp.path()));

        // Open or create should work
        let conn = open_or_create(temp.path()).expect("Failed to open_or_create");

        // Database should now exist
        assert!(has_database(temp.path()));

        // Should be initialized
        assert!(is_initialized(&conn));
    }

    #[test]
    fn test_open_or_create_creates_harness_folder() {
        let temp = create_temp_project();

        // .harness folder should not exist yet
        assert!(!has_harness_folder(temp.path()));

        // Open or create
        open_or_create(temp.path()).expect("Failed to open_or_create");

        // .harness folder should now exist
        assert!(has_harness_folder(temp.path()));
    }

    #[test]
    fn test_open_works_after_create() {
        let temp = create_temp_project();

        // Create database
        let conn1 = open_or_create(temp.path()).expect("Failed to create");
        drop(conn1);

        // Open should work
        let conn2 = open(temp.path()).expect("Failed to open");
        assert!(is_initialized(&conn2));
    }

    #[test]
    fn test_open_or_create_is_idempotent() {
        let temp = create_temp_project();

        // Call multiple times
        let conn1 = open_or_create(temp.path()).expect("First open_or_create failed");
        drop(conn1);

        let conn2 = open_or_create(temp.path()).expect("Second open_or_create failed");
        drop(conn2);

        let conn3 = open_or_create(temp.path()).expect("Third open_or_create failed");

        // Should still work
        assert!(is_initialized(&conn3));
    }

    // -------------------------------------------------------------------------
    // In-memory tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_open_in_memory() {
        let conn = open_in_memory().expect("Failed to open in-memory database");
        assert!(is_initialized(&conn));
    }

    #[test]
    fn test_open_in_memory_allows_operations() {
        let conn = open_in_memory().expect("Failed to open in-memory database");

        // Should be able to insert data
        conn.execute(
            "INSERT INTO project_tasks (id, title, created_at, updated_at)
             VALUES ('01ARZ3NDEKTSV4RRFFQ69G5FAV', 'Test task', '2026-01-04T12:00:00Z', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Failed to insert task");

        // Should be able to query data
        let count: i32 = conn
            .query_row("SELECT COUNT(*) FROM project_tasks", [], |row| row.get(0))
            .expect("Failed to count tasks");

        assert_eq!(count, 1);
    }

    // -------------------------------------------------------------------------
    // Stats tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_db_stats_empty_db() {
        let conn = open_in_memory().expect("Failed to open in-memory database");
        let stats = DbStats::collect(&conn, None).expect("Failed to collect stats");

        assert_eq!(stats.task_count, 0);
        assert_eq!(stats.step_count, 0);
        assert_eq!(stats.session_count, 0);
        assert_eq!(stats.progress_count, 0);
        assert!(stats.task_by_status.is_empty());
    }

    #[test]
    fn test_db_stats_with_data() {
        let conn = open_in_memory().expect("Failed to open in-memory database");

        // Insert some data
        conn.execute(
            "INSERT INTO project_tasks (id, title, status, created_at, updated_at)
             VALUES ('01ARZ3NDEKTSV4RRFFQ69G5FAV', 'Task 1', 'TODO', '2026-01-04T12:00:00Z', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Insert task 1");

        conn.execute(
            "INSERT INTO project_tasks (id, title, status, created_at, updated_at)
             VALUES ('01BSZ3NDEKTSV4RRFFQ69G5FBV', 'Task 2', 'TODO', '2026-01-04T12:00:00Z', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Insert task 2");

        conn.execute(
            "INSERT INTO project_tasks (id, title, status, created_at, updated_at)
             VALUES ('01CSZ3NDEKTSV4RRFFQ69G5FCV', 'Task 3', 'DONE', '2026-01-04T12:00:00Z', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Insert task 3");

        conn.execute(
            "INSERT INTO task_steps (id, description, created_at)
             VALUES ('task#01ARZ3NDEKTSV4RRFFQ69G5FAV#01DSZ3NDEKTSV4RRFFQ69G5FDV', 'Step 1', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Insert step");

        let stats = DbStats::collect(&conn, None).expect("Failed to collect stats");

        assert_eq!(stats.task_count, 3);
        assert_eq!(stats.step_count, 1);
        assert_eq!(stats.task_by_status.get("TODO"), Some(&2));
        assert_eq!(stats.task_by_status.get("DONE"), Some(&1));
    }

    #[test]
    fn test_db_stats_file_size() {
        let temp = create_temp_project();
        let conn = open_or_create(temp.path()).expect("Failed to create database");

        // Insert some data
        conn.execute(
            "INSERT INTO project_tasks (id, title, created_at, updated_at)
             VALUES ('01ARZ3NDEKTSV4RRFFQ69G5FAV', 'Task', '2026-01-04T12:00:00Z', '2026-01-04T12:00:00Z')",
            [],
        )
        .expect("Insert task");

        let db_path = get_db_path(temp.path());
        let stats = DbStats::collect(&conn, Some(&db_path)).expect("Failed to collect stats");

        // File should have some size > 0
        assert!(stats.file_size_bytes > 0);
    }
}

