        let task = create_test_task("Full task")
            .with_description("A description")
            .with_status(TaskStatus::Doing)
            .with_category("core")
            .with_sort_order(5.5);

        create_task(&conn, &task).expect("Failed to create task");

        let retrieved = get_task(&conn, &task.id).expect("Failed to get task").unwrap();
        assert_eq!(retrieved.description, Some("A description".to_string()));
        assert_eq!(retrieved.status, TaskStatus::Doing);
        assert_eq!(retrieved.category, Some("core".to_string()));
        assert_eq!(retrieved.sort_order, 5.5);
    }

