    // Read tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_get_task_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let result = get_task(&conn, "01ARZ3NDEKTSV4RRFFQ69G5FAV").expect("Query failed");
        assert!(result.is_none());
    }

    #[test]
    fn test_list_tasks_empty() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let result = list_tasks(&conn, None, None).expect("Failed to list tasks");

        assert!(result.items.is_empty());
        assert!(!result.has_next);
        assert!(!result.has_prev);
    }

    #[test]
    fn test_list_tasks_returns_all() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        for i in 0..5 {
            let task = create_test_task(&format!("Task {}", i)).with_sort_order(i as f64);
            create_task(&conn, &task).expect("Failed to create task");
        }

        let result = list_tasks(&conn, None, None).expect("Failed to list tasks");
        assert_eq!(result.items.len(), 5);
        assert!(!result.has_next);
    }

    #[test]
    fn test_list_tasks_pagination() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        for i in 0..10 {
            let task = create_test_task(&format!("Task {}", i)).with_sort_order(i as f64);
            create_task(&conn, &task).expect("Failed to create task");
        }

        // First page
        let page1 = list_tasks(&conn, None, Some(3)).expect("Failed to list tasks");
        assert_eq!(page1.items.len(), 3);
        assert!(page1.has_next);
        assert!(!page1.has_prev);
        assert!(page1.next_cursor.is_some());

        // Second page
        let page2 = list_tasks(&conn, page1.next_cursor.as_deref(), Some(3)).expect("Failed to list tasks");
        assert_eq!(page2.items.len(), 3);
        assert!(page2.has_next);
        assert!(page2.has_prev);

        // Verify items are different
        assert_ne!(page1.items[0].id, page2.items[0].id);
    }

    #[test]
    fn test_list_tasks_by_status() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let task1 = create_test_task("Todo 1").with_status(TaskStatus::Todo);
        let task2 = create_test_task("Todo 2").with_status(TaskStatus::Todo);
        let task3 = create_test_task("Done").with_status(TaskStatus::Done);

        create_task(&conn, &task1).expect("Create task1");
        create_task(&conn, &task2).expect("Create task2");
        create_task(&conn, &task3).expect("Create task3");

        let todos = list_tasks_by_status(&conn, TaskStatus::Todo, None, None).expect("List todos");
        assert_eq!(todos.items.len(), 2);

        let dones = list_tasks_by_status(&conn, TaskStatus::Done, None, None).expect("List dones");
        assert_eq!(dones.items.len(), 1);
    }

    #[test]
    fn test_search_tasks() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let task1 = create_test_task("Fix critical bug").with_description("Memory leak issue");
        let task2 = create_test_task("Add feature").with_description("New feature request");
        let task3 = create_test_task("Bug report").with_description("Minor issue");

        create_task(&conn, &task1).expect("Create task1");
        create_task(&conn, &task2).expect("Create task2");
        create_task(&conn, &task3).expect("Create task3");

        // Search for "bug"
        let results = search_tasks(&conn, "bug", None).expect("Search failed");
        assert_eq!(results.len(), 2);

        // Search for "feature"
        let results = search_tasks(&conn, "feature", None).expect("Search failed");
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].title, "Add feature");

        // Search for "memory"
        let results = search_tasks(&conn, "memory", None).expect("Search failed");
        assert_eq!(results.len(), 1);
        assert!(results[0].description.as_ref().unwrap().contains("Memory"));
    }

    #[test]
    fn test_count_tasks_by_status() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let task1 = create_test_task("T1").with_status(TaskStatus::Todo);
        let task2 = create_test_task("T2").with_status(TaskStatus::Todo);
        let task3 = create_test_task("T3").with_status(TaskStatus::Done);

        create_task(&conn, &task1).expect("Create task1");
        create_task(&conn, &task2).expect("Create task2");
        create_task(&conn, &task3).expect("Create task3");

        let counts = count_tasks_by_status(&conn).expect("Count failed");
        assert_eq!(counts.get("TODO"), Some(&2));
        assert_eq!(counts.get("DONE"), Some(&1));
    }

    // -------------------------------------------------------------------------
    // Update tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_update_task_title() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task("Original");
        create_task(&conn, &task).expect("Create task");

        let updated = update_task(&conn, &task.id, TaskUpdate {
            title: Some("Updated".to_string()),
            ..Default::default()
        }).expect("Update failed");

        assert!(updated);

        let retrieved = get_task(&conn, &task.id).expect("Get failed").unwrap();
        assert_eq!(retrieved.title, "Updated");
    }

    #[test]
    fn test_update_task_status() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task("Task");
        create_task(&conn, &task).expect("Create task");

        set_task_status(&conn, &task.id, TaskStatus::Done).expect("Update failed");

        let retrieved = get_task(&conn, &task.id).expect("Get failed").unwrap();
        assert_eq!(retrieved.status, TaskStatus::Done);
    }

    #[test]
    fn test_update_task_passed() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task("Task");
        create_task(&conn, &task).expect("Create task");

        assert!(!task.is_passed);

        set_task_passed(&conn, &task.id, true).expect("Update failed");

        let retrieved = get_task(&conn, &task.id).expect("Get failed").unwrap();
        assert!(retrieved.is_passed);
    }

    #[test]
    fn test_update_task_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let updated = update_task(&conn, "01ARZ3NDEKTSV4RRFFQ69G5FAV", TaskUpdate {
            title: Some("New".to_string()),
            ..Default::default()
        }).expect("Update should not error");

        assert!(!updated);
    }

    // -------------------------------------------------------------------------
    // Delete tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_delete_task() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task("To delete");
        create_task(&conn, &task).expect("Create task");

        let deleted = delete_task(&conn, &task.id).expect("Delete failed");
        assert!(deleted);

        let retrieved = get_task(&conn, &task.id).expect("Get failed");
        assert!(retrieved.is_none());
    }

    #[test]
    fn test_delete_task_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let deleted = delete_task(&conn, "01ARZ3NDEKTSV4RRFFQ69G5FAV").expect("Delete should not error");
        assert!(!deleted);
    }

    // -------------------------------------------------------------------------
    // Reorder tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_get_order_after_empty() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let order = get_order_after(&conn, None).expect("Get order failed");
        assert_eq!(order, 0.0);
    }

    #[test]
    fn test_get_order_after_at_beginning() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let task = create_test_task("Task").with_sort_order(5.0);
        create_task(&conn, &task).expect("Create task");

        let order = get_order_after(&conn, None).expect("Get order failed");
        assert!(order < 5.0); // Should be before 5.0
    }

    #[test]
    fn test_get_order_after_between_tasks() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let task1 = create_test_task("Task 1").with_sort_order(1.0);
        let task2 = create_test_task("Task 2").with_sort_order(2.0);
        create_task(&conn, &task1).expect("Create task1");
        create_task(&conn, &task2).expect("Create task2");

        let order = get_order_after(&conn, Some(&task1.id)).expect("Get order failed");
        assert!(order > 1.0 && order < 2.0); // Should be between 1.0 and 2.0
    }

    #[test]
    fn test_reorder_task() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let task1 = create_test_task("Task 1").with_sort_order(1.0);
        let task2 = create_test_task("Task 2").with_sort_order(2.0);
        let task3 = create_test_task("Task 3").with_sort_order(3.0);
        create_task(&conn, &task1).expect("Create task1");
        create_task(&conn, &task2).expect("Create task2");
        create_task(&conn, &task3).expect("Create task3");

        // Move task3 after task1 (between task1 and task2)
        reorder_task(&conn, &task3.id, Some(&task1.id)).expect("Reorder failed");

        let updated = get_task(&conn, &task3.id).expect("Get failed").unwrap();
        assert!(updated.sort_order > 1.0 && updated.sort_order < 2.0);
    }

    // -------------------------------------------------------------------------
    // Cursor encoding tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_cursor_encode_decode() {
        let id = "01ARZ3NDEKTSV4RRFFQ69G5FAV";
        let encoded = encode_cursor(id);
        let decoded = decode_cursor(&encoded).expect("Decode failed");
        assert_eq!(decoded, id);
    }
}

