        create_task(&conn, &task2).expect("Create task2");
        create_task(&conn, &task3).expect("Create task3");

        // Move task3 after task1 (between task1 and task2)
        reorder_task(&conn, &task3.id, Some(&task1.id)).expect("Reorder failed");

        let updated = get_task(&conn, &task3.id).expect("Get failed").unwrap();
        assert!(updated.sort_order > 1.0 && updated.sort_order < 2.0);
    }

    // -------------------------------------------------------------------------
    // Cursor encoding tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_cursor_encode_decode() {
        let id = "01ARZ3NDEKTSV4RRFFQ69G5FAV";
        let encoded = encode_cursor(id);
        let decoded = decode_cursor(&encoded).expect("Decode failed");
        assert_eq!(decoded, id);
    }
}

