//! Task step CRUD operations.
//!
//! This module provides Create, Read, Update, Delete operations for task steps.
//! Steps are checklist items within a task, using composite IDs for efficient querying.
//!
//! ## Composite ID Format
//!
//! `task#{task_ulid}#{step_ulid}`
//!
//! This allows efficient prefix queries: `WHERE id GLOB 'task#<task_id>#*'`

use chrono::Utc;
use rusqlite::{params, Connection, OptionalExtension};

use super::types::TaskStep;
use super::DbResult;

// =============================================================================
// CREATE
// =============================================================================

/// Create a new step for a task.
pub fn create_step(conn: &Connection, step: &TaskStep) -> DbResult<()> {
    conn.execute(
        r#"
        INSERT INTO task_steps (id, description, is_completed, created_at)
        VALUES (?1, ?2, ?3, ?4)
        "#,
        params![
            step.id,
            step.description,
            if step.is_completed { "true" } else { "false" },
            step.created_at.to_rfc3339(),
        ],
    )?;
    Ok(())
}

/// Create a new step for a task with just description.
///
/// Generates the step ID automatically.
pub fn add_step(conn: &Connection, task_id: &str, description: &str) -> DbResult<TaskStep> {
    let step = TaskStep::new(task_id, description)?;
    create_step(conn, &step)?;
    Ok(step)
}

// =============================================================================
// READ
// =============================================================================

/// Get a step by ID.
pub fn get_step(conn: &Connection, id: &str) -> DbResult<Option<TaskStep>> {
    let result = conn
        .query_row(
            r#"
            SELECT id, description, is_completed, created_at
            FROM task_steps
            WHERE id = ?1
            "#,
            [id],
            |row| row_to_step(row),
        )
        .optional()?;
    Ok(result)
}

/// List all steps for a task.
///
/// Returns steps ordered by creation time (ULID order).
pub fn list_steps(conn: &Connection, task_id: &str) -> DbResult<Vec<TaskStep>> {
    let pattern = TaskStep::glob_pattern(task_id);

    let mut stmt = conn.prepare(
        r#"
        SELECT id, description, is_completed, created_at
        FROM task_steps
        WHERE id GLOB ?1
        ORDER BY id ASC
        "#,
    )?;

    let rows = stmt.query_map([pattern], |row| row_to_step(row))?;

    let mut steps = Vec::new();
    for row in rows {
        steps.push(row?);
    }

    Ok(steps)
}

/// Count steps for a task.
pub fn count_steps(conn: &Connection, task_id: &str) -> DbResult<i64> {
    let pattern = TaskStep::glob_pattern(task_id);

    let count: i64 = conn.query_row(
        "SELECT COUNT(*) FROM task_steps WHERE id GLOB ?1",
        [pattern],
        |row| row.get(0),
    )?;

    Ok(count)
}

/// Count completed steps for a task.
pub fn count_completed_steps(conn: &Connection, task_id: &str) -> DbResult<i64> {
    let pattern = TaskStep::glob_pattern(task_id);

    let count: i64 = conn.query_row(
        "SELECT COUNT(*) FROM task_steps WHERE id GLOB ?1 AND is_completed = 'true'",
        [pattern],
        |row| row.get(0),
    )?;

    Ok(count)
}

/// Get step completion progress for a task.
///
/// Returns (completed, total).
pub fn get_step_progress(conn: &Connection, task_id: &str) -> DbResult<(i64, i64)> {
    let total = count_steps(conn, task_id)?;
    let completed = count_completed_steps(conn, task_id)?;
    Ok((completed, total))
}

// =============================================================================
// UPDATE
// =============================================================================

/// Update step description.
pub fn update_step_description(conn: &Connection, id: &str, description: &str) -> DbResult<bool> {
    let rows_affected = conn.execute(
        "UPDATE task_steps SET description = ?1 WHERE id = ?2",
        params![description, id],
    )?;
    Ok(rows_affected > 0)
}

/// Set step completion status.
pub fn set_step_completed(conn: &Connection, id: &str, completed: bool) -> DbResult<bool> {
    let rows_affected = conn.execute(
        "UPDATE task_steps SET is_completed = ?1 WHERE id = ?2",
        params![if completed { "true" } else { "false" }, id],
    )?;
    Ok(rows_affected > 0)
}

/// Mark step as completed.
pub fn complete_step(conn: &Connection, id: &str) -> DbResult<bool> {
    set_step_completed(conn, id, true)
}

/// Mark step as not completed.
pub fn uncomplete_step(conn: &Connection, id: &str) -> DbResult<bool> {
    set_step_completed(conn, id, false)
}

/// Toggle step completion status.
pub fn toggle_step(conn: &Connection, id: &str) -> DbResult<bool> {
    let step = get_step(conn, id)?;
    if let Some(step) = step {
        set_step_completed(conn, id, !step.is_completed)
    } else {
        Ok(false)
    }
}

// =============================================================================
// DELETE
// =============================================================================

/// Delete a step by ID.
pub fn delete_step(conn: &Connection, id: &str) -> DbResult<bool> {
    let rows_affected = conn.execute("DELETE FROM task_steps WHERE id = ?1", [id])?;
    Ok(rows_affected > 0)
}

/// Delete all steps for a task.
pub fn delete_steps_for_task(conn: &Connection, task_id: &str) -> DbResult<i64> {
    let pattern = TaskStep::glob_pattern(task_id);
    let rows_affected = conn.execute("DELETE FROM task_steps WHERE id GLOB ?1", [pattern])?;
    Ok(rows_affected as i64)
}

// =============================================================================
// HELPERS
// =============================================================================

fn row_to_step(row: &rusqlite::Row) -> rusqlite::Result<TaskStep> {
    let is_completed_str: String = row.get(2)?;
    let created_at_str: String = row.get(3)?;

    Ok(TaskStep {
        id: row.get(0)?,
        description: row.get(1)?,
        is_completed: is_completed_str == "true",
        created_at: chrono::DateTime::parse_from_rfc3339(&created_at_str)
            .map(|dt| dt.with_timezone(&Utc))
            .unwrap_or_else(|_| Utc::now()),
    })
}

