        assert_eq!(steps.len(), 3);
    }

    // -------------------------------------------------------------------------
    // Read tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_get_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "My step").expect("Add step");
