    }

    #[test]
    fn test_get_step_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let result = get_step(&conn, "task#01ARZ3NDEKTSV4RRFFQ69G5FAV#01BSZ3NDEKTSV4RRFFQ69G5FBV")
