fn row_to_step(row: &rusqlite::Row) -> rusqlite::Result<TaskStep> {
    let is_completed_str: String = row.get(2)?;
    let created_at_str: String = row.get(3)?;

    Ok(TaskStep {
        id: row.get(0)?,
        description: row.get(1)?,
        is_completed: is_completed_str == "true",
        created_at: chrono::DateTime::parse_from_rfc3339(&created_at_str)
            .map(|dt| dt.with_timezone(&Utc))
            .unwrap_or_else(|_| Utc::now()),
    })
}

// =============================================================================
// TESTS
// =============================================================================

#[cfg(test)]
mod tests {
    use super::*;
    use crate::db::connection::open_in_memory;
    use crate::db::types::ProjectTask;
    use crate::db::tasks::create_task;

    fn create_test_task(conn: &Connection, title: &str) -> ProjectTask {
        let task = ProjectTask::new(title);
        create_task(conn, &task).expect("Failed to create task");
        task
    }

    // -------------------------------------------------------------------------
    // Create tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_add_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "First step").expect("Failed to add step");

        assert!(step.id.starts_with(&format!("task#{}#", task.id)));
        assert_eq!(step.description, "First step");
        assert!(!step.is_completed);
    }

    #[test]
    fn test_add_multiple_steps() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        add_step(&conn, &task.id, "Step 1").expect("Add step 1");
        add_step(&conn, &task.id, "Step 2").expect("Add step 2");
        add_step(&conn, &task.id, "Step 3").expect("Add step 3");

        let steps = list_steps(&conn, &task.id).expect("List steps");
        assert_eq!(steps.len(), 3);
    }

    // -------------------------------------------------------------------------
    // Read tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_get_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "My step").expect("Add step");
        let retrieved = get_step(&conn, &step.id).expect("Get step").unwrap();

        assert_eq!(retrieved.id, step.id);
        assert_eq!(retrieved.description, "My step");
    }

    #[test]
    fn test_get_step_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let result = get_step(&conn, "task#01ARZ3NDEKTSV4RRFFQ69G5FAV#01BSZ3NDEKTSV4RRFFQ69G5FBV")
            .expect("Query failed");
        assert!(result.is_none());
    }

    #[test]
    fn test_list_steps_empty() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let steps = list_steps(&conn, &task.id).expect("List steps");
        assert!(steps.is_empty());
    }

    #[test]
    fn test_list_steps_ordered_by_creation() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step1 = add_step(&conn, &task.id, "First").expect("Add step 1");
        std::thread::sleep(std::time::Duration::from_millis(2)); // Ensure different ULID
        let step2 = add_step(&conn, &task.id, "Second").expect("Add step 2");
        std::thread::sleep(std::time::Duration::from_millis(2));
        let step3 = add_step(&conn, &task.id, "Third").expect("Add step 3");

        let steps = list_steps(&conn, &task.id).expect("List steps");
        assert_eq!(steps.len(), 3);
        assert_eq!(steps[0].id, step1.id);
        assert_eq!(steps[1].id, step2.id);
        assert_eq!(steps[2].id, step3.id);
    }

    #[test]
    fn test_list_steps_only_for_task() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task1 = create_test_task(&conn, "Task 1");
        let task2 = create_test_task(&conn, "Task 2");

        add_step(&conn, &task1.id, "T1 Step 1").expect("Add step");
        add_step(&conn, &task1.id, "T1 Step 2").expect("Add step");
        add_step(&conn, &task2.id, "T2 Step 1").expect("Add step");

        let task1_steps = list_steps(&conn, &task1.id).expect("List task1 steps");
        let task2_steps = list_steps(&conn, &task2.id).expect("List task2 steps");

        assert_eq!(task1_steps.len(), 2);
        assert_eq!(task2_steps.len(), 1);
    }

    #[test]
    fn test_count_steps() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        add_step(&conn, &task.id, "Step 1").expect("Add step");
        add_step(&conn, &task.id, "Step 2").expect("Add step");

        let count = count_steps(&conn, &task.id).expect("Count steps");
        assert_eq!(count, 2);
    }

    #[test]
    fn test_get_step_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step1 = add_step(&conn, &task.id, "Step 1").expect("Add step");
        add_step(&conn, &task.id, "Step 2").expect("Add step");
        let step3 = add_step(&conn, &task.id, "Step 3").expect("Add step");

        // Complete 2 of 3
        complete_step(&conn, &step1.id).expect("Complete step");
        complete_step(&conn, &step3.id).expect("Complete step");

        let (completed, total) = get_step_progress(&conn, &task.id).expect("Get progress");
        assert_eq!(total, 3);
        assert_eq!(completed, 2);
    }

    // -------------------------------------------------------------------------
    // Update tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_update_step_description() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "Original").expect("Add step");
        update_step_description(&conn, &step.id, "Updated").expect("Update step");

        let retrieved = get_step(&conn, &step.id).expect("Get step").unwrap();
        assert_eq!(retrieved.description, "Updated");
    }

    #[test]
    fn test_complete_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "Step").expect("Add step");
        assert!(!step.is_completed);

        complete_step(&conn, &step.id).expect("Complete step");

        let retrieved = get_step(&conn, &step.id).expect("Get step").unwrap();
        assert!(retrieved.is_completed);
    }

    #[test]
    fn test_uncomplete_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "Step").expect("Add step");
        complete_step(&conn, &step.id).expect("Complete step");
        uncomplete_step(&conn, &step.id).expect("Uncomplete step");

        let retrieved = get_step(&conn, &step.id).expect("Get step").unwrap();
        assert!(!retrieved.is_completed);
    }

    #[test]
    fn test_toggle_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "Step").expect("Add step");

        // Toggle on
        toggle_step(&conn, &step.id).expect("Toggle step");
        let retrieved = get_step(&conn, &step.id).expect("Get step").unwrap();
        assert!(retrieved.is_completed);

        // Toggle off
        toggle_step(&conn, &step.id).expect("Toggle step");
        let retrieved = get_step(&conn, &step.id).expect("Get step").unwrap();
        assert!(!retrieved.is_completed);
    }

    // -------------------------------------------------------------------------
    // Delete tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_delete_step() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        let step = add_step(&conn, &task.id, "Step").expect("Add step");
        let deleted = delete_step(&conn, &step.id).expect("Delete step");
        assert!(deleted);

        let retrieved = get_step(&conn, &step.id).expect("Get step");
        assert!(retrieved.is_none());
    }

    #[test]
    fn test_delete_step_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let deleted = delete_step(&conn, "task#01ARZ3NDEKTSV4RRFFQ69G5FAV#01BSZ3NDEKTSV4RRFFQ69G5FBV")
            .expect("Delete should not error");
        assert!(!deleted);
    }

    #[test]
    fn test_delete_steps_for_task() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task(&conn, "Test task");

        add_step(&conn, &task.id, "Step 1").expect("Add step");
        add_step(&conn, &task.id, "Step 2").expect("Add step");
        add_step(&conn, &task.id, "Step 3").expect("Add step");

        let deleted = delete_steps_for_task(&conn, &task.id).expect("Delete steps");
        assert_eq!(deleted, 3);

        let steps = list_steps(&conn, &task.id).expect("List steps");
        assert!(steps.is_empty());
    }
}

