//! Task CRUD operations.
//!
//! This module provides Create, Read, Update, Delete operations for project tasks.
//! Features:
//! - Full CRUD operations
//! - Pagination with cursor-based navigation
//! - Full-text search via FTS5
//! - Status filtering
//! - Reordering with fractional sort_order

use chrono::Utc;
use rusqlite::{params, Connection, OptionalExtension};

use super::types::{PaginatedResult, ProjectTask, TaskStatus};
use super::DbResult;

/// Default page size for list operations.
pub const DEFAULT_PAGE_SIZE: usize = 50;

// =============================================================================
// CREATE
// =============================================================================

/// Create a new task.
pub fn create_task(conn: &Connection, task: &ProjectTask) -> DbResult<()> {
    conn.execute(
        r#"
        INSERT INTO project_tasks (id, title, description, status, category, sort_order, is_passed, created_at, updated_at)
        VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, ?9)
        "#,
        params![
            task.id,
            task.title,
            task.description,
            task.status.as_str(),
            task.category,
            task.sort_order,
            if task.is_passed { "true" } else { "false" },
            task.created_at.to_rfc3339(),
            task.updated_at.to_rfc3339(),
        ],
    )?;
    Ok(())
}

// =============================================================================
// READ
// =============================================================================

/// Get a task by ID.
pub fn get_task(conn: &Connection, id: &str) -> DbResult<Option<ProjectTask>> {
    let result = conn
        .query_row(
            r#"
            SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
            FROM project_tasks
            WHERE id = ?1
            "#,
            [id],
            |row| row_to_task(row),
        )
        .optional()?;
    Ok(result)
}

/// List all tasks with pagination.
///
/// Returns tasks ordered by sort_order, then created_at.
pub fn list_tasks(
    conn: &Connection,
    cursor: Option<&str>,
    limit: Option<usize>,
) -> DbResult<PaginatedResult<ProjectTask>> {
    let limit = limit.unwrap_or(DEFAULT_PAGE_SIZE);

    // Decode cursor if present
    let after_id = cursor.map(|c| decode_cursor(c)).transpose()?;

    let mut tasks = Vec::new();

    if let Some(after_id) = after_id {
        // Get the sort_order of the cursor task
        let cursor_order: Option<f64> = conn
            .query_row(
                "SELECT sort_order FROM project_tasks WHERE id = ?1",
                [&after_id],
                |row| row.get(0),
            )
            .optional()?;

        if let Some(order) = cursor_order {
            // Get tasks after the cursor
            let mut stmt = conn.prepare(
                r#"
                SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
                FROM project_tasks
                WHERE (sort_order > ?1) OR (sort_order = ?1 AND id > ?2)
                ORDER BY sort_order ASC, id ASC
                LIMIT ?3
                "#,
            )?;

            let rows = stmt.query_map(params![order, after_id, (limit + 1) as i64], |row| row_to_task(row))?;
            for row in rows {
                tasks.push(row?);
            }
        }
    } else {
        // No cursor, get from the beginning
        let mut stmt = conn.prepare(
            r#"
            SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
            FROM project_tasks
            ORDER BY sort_order ASC, id ASC
            LIMIT ?1
            "#,
        )?;

        let rows = stmt.query_map([(limit + 1) as i64], |row| row_to_task(row))?;
        for row in rows {
            tasks.push(row?);
        }
    }

    // Check if there are more results
    let has_next = tasks.len() > limit;
    if has_next {
        tasks.pop(); // Remove the extra item
    }

    // Has prev if we used a cursor
    let has_prev = cursor.is_some();

    // Generate cursors
    let next_cursor = if has_next {
        tasks.last().map(|t| encode_cursor(&t.id))
    } else {
        None
    };

    let prev_cursor = if has_prev {
        tasks.first().map(|t| encode_cursor(&t.id))
    } else {
        None
    };

    Ok(PaginatedResult::new(tasks, has_next, has_prev, next_cursor, prev_cursor))
}

/// List tasks by status with pagination.
pub fn list_tasks_by_status(
    conn: &Connection,
    status: TaskStatus,
    cursor: Option<&str>,
    limit: Option<usize>,
) -> DbResult<PaginatedResult<ProjectTask>> {
    let limit = limit.unwrap_or(DEFAULT_PAGE_SIZE);
    let status_str = status.as_str();

    let after_id = cursor.map(|c| decode_cursor(c)).transpose()?;

    let mut tasks = Vec::new();

    if let Some(after_id) = after_id {
        let cursor_order: Option<f64> = conn
            .query_row(
                "SELECT sort_order FROM project_tasks WHERE id = ?1",
                [&after_id],
                |row| row.get(0),
            )
            .optional()?;

        if let Some(order) = cursor_order {
            let mut stmt = conn.prepare(
                r#"
                SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
                FROM project_tasks
                WHERE status = ?1 AND ((sort_order > ?2) OR (sort_order = ?2 AND id > ?3))
                ORDER BY sort_order ASC, id ASC
                LIMIT ?4
                "#,
            )?;

            let rows = stmt.query_map(params![status_str, order, after_id, (limit + 1) as i64], |row| {
                row_to_task(row)
            })?;
            for row in rows {
                tasks.push(row?);
            }
        }
    } else {
        let mut stmt = conn.prepare(
            r#"
            SELECT id, title, description, status, category, sort_order, is_passed, created_at, updated_at
            FROM project_tasks
            WHERE status = ?1
            ORDER BY sort_order ASC, id ASC
            LIMIT ?2
            "#,
        )?;

        let rows = stmt.query_map(params![status_str, (limit + 1) as i64], |row| row_to_task(row))?;
        for row in rows {
            tasks.push(row?);
        }
    }

    let has_next = tasks.len() > limit;
    if has_next {
        tasks.pop();
    }

    let has_prev = cursor.is_some();

    let next_cursor = if has_next {
        tasks.last().map(|t| encode_cursor(&t.id))
    } else {
        None
    };

    let prev_cursor = if has_prev {
        tasks.first().map(|t| encode_cursor(&t.id))
    } else {
        None
    };

    Ok(PaginatedResult::new(tasks, has_next, has_prev, next_cursor, prev_cursor))
}

/// Search tasks using full-text search.
pub fn search_tasks(
    conn: &Connection,
    query: &str,
    limit: Option<usize>,
) -> DbResult<Vec<ProjectTask>> {
    let limit = limit.unwrap_or(DEFAULT_PAGE_SIZE);

    let mut stmt = conn.prepare(
        r#"
        SELECT p.id, p.title, p.description, p.status, p.category, p.sort_order, p.is_passed, p.created_at, p.updated_at
        FROM project_tasks p
        JOIN project_tasks_fts fts ON p.rowid = fts.rowid
        WHERE project_tasks_fts MATCH ?1
        ORDER BY rank
        LIMIT ?2
        "#,
    )?;

    let rows = stmt.query_map(params![query, limit as i64], |row| row_to_task(row))?;

    let mut tasks = Vec::new();
    for row in rows {
        tasks.push(row?);
    }

    Ok(tasks)
}

/// Count tasks by status.
pub fn count_tasks_by_status(conn: &Connection) -> DbResult<std::collections::HashMap<String, i64>> {
    let mut stmt = conn.prepare(
        "SELECT status, COUNT(*) FROM project_tasks GROUP BY status",
    )?;

    let rows = stmt.query_map([], |row| {
        Ok((row.get::<_, String>(0)?, row.get::<_, i64>(1)?))
    })?;

    let mut counts = std::collections::HashMap::new();
    for row in rows {
        let (status, count) = row?;
        counts.insert(status, count);
    }

    Ok(counts)
}

// =============================================================================
// UPDATE
// =============================================================================

/// Update fields for a task.
#[derive(Default)]
pub struct TaskUpdate {
    pub title: Option<String>,
    pub description: Option<Option<String>>,
    pub status: Option<TaskStatus>,
    pub category: Option<Option<String>>,
    pub sort_order: Option<f64>,
    pub is_passed: Option<bool>,
}

/// Update a task with the given changes.
pub fn update_task(conn: &Connection, id: &str, update: TaskUpdate) -> DbResult<bool> {
    let mut updates = Vec::new();
    let mut values: Vec<Box<dyn rusqlite::ToSql>> = Vec::new();

    if let Some(ref title) = update.title {
        updates.push("title = ?");
        values.push(Box::new(title.clone()));
    }

    if let Some(ref desc) = update.description {
        updates.push("description = ?");
        values.push(Box::new(desc.clone()));
    }

    if let Some(status) = update.status {
        updates.push("status = ?");
        values.push(Box::new(status.as_str().to_string()));
    }

    if let Some(ref category) = update.category {
        updates.push("category = ?");
        values.push(Box::new(category.clone()));
    }

    if let Some(sort_order) = update.sort_order {
        updates.push("sort_order = ?");
        values.push(Box::new(sort_order));
    }

    if let Some(is_passed) = update.is_passed {
        updates.push("is_passed = ?");
        values.push(Box::new(if is_passed { "true" } else { "false" }));
    }

    if updates.is_empty() {
        return Ok(false);
    }

    // Always update updated_at
    updates.push("updated_at = ?");
    values.push(Box::new(Utc::now().to_rfc3339()));

    // Add ID at the end
    values.push(Box::new(id.to_string()));

    let sql = format!(
        "UPDATE project_tasks SET {} WHERE id = ?",
        updates.join(", ")
    );

    let params: Vec<&dyn rusqlite::ToSql> = values.iter().map(|v| v.as_ref()).collect();
    let rows_affected = conn.execute(&sql, params.as_slice())?;

    Ok(rows_affected > 0)
}

/// Set task status.
pub fn set_task_status(conn: &Connection, id: &str, status: TaskStatus) -> DbResult<bool> {
    update_task(conn, id, TaskUpdate {
        status: Some(status),
        ..Default::default()
    })
}

/// Set task as passed.
pub fn set_task_passed(conn: &Connection, id: &str, passed: bool) -> DbResult<bool> {
    update_task(conn, id, TaskUpdate {
        is_passed: Some(passed),
        ..Default::default()
    })
}

// =============================================================================
// DELETE
// =============================================================================

/// Delete a task by ID.
///
/// Note: This also needs to delete related task_steps (handled by caller or cascade).
pub fn delete_task(conn: &Connection, id: &str) -> DbResult<bool> {
    let rows_affected = conn.execute("DELETE FROM project_tasks WHERE id = ?1", [id])?;
    Ok(rows_affected > 0)
}

// =============================================================================
// REORDER
// =============================================================================

/// Get the sort order for positioning after another task.
///
/// If after_id is None, positions at the beginning.
pub fn get_order_after(conn: &Connection, after_id: Option<&str>) -> DbResult<f64> {
    if let Some(after_id) = after_id {
        // Get the order of the after task
        let after_order: f64 = conn.query_row(
            "SELECT sort_order FROM project_tasks WHERE id = ?1",
            [after_id],
            |row| row.get(0),
        )?;

        // Get the next task's order (if any)
        let next_order: Option<f64> = conn
            .query_row(
                "SELECT sort_order FROM project_tasks WHERE sort_order > ?1 ORDER BY sort_order ASC LIMIT 1",
                [after_order],
                |row| row.get(0),
            )
            .optional()?;

        // Position between after and next
        match next_order {
            Some(next) => Ok((after_order + next) / 2.0),
            None => Ok(after_order + 1.0),
        }
    } else {
        // Position at the beginning
        let min_order: Option<f64> = conn
            .query_row(
                "SELECT MIN(sort_order) FROM project_tasks",
                [],
                |row| row.get(0),
            )
            .optional()?
            .flatten();

        match min_order {
            Some(min) => Ok(min - 1.0),
            None => Ok(0.0),
        }
    }
}

/// Reorder a task to be after another task.
pub fn reorder_task(conn: &Connection, id: &str, after_id: Option<&str>) -> DbResult<bool> {
    let new_order = get_order_after(conn, after_id)?;
    update_task(conn, id, TaskUpdate {
        sort_order: Some(new_order),
        ..Default::default()
    })
}

// =============================================================================
// HELPERS
// =============================================================================

fn row_to_task(row: &rusqlite::Row) -> rusqlite::Result<ProjectTask> {
    let status_str: String = row.get(3)?;
    let is_passed_str: String = row.get(6)?;
    let created_at_str: String = row.get(7)?;
    let updated_at_str: String = row.get(8)?;

    Ok(ProjectTask {
        id: row.get(0)?,
        title: row.get(1)?,
        description: row.get(2)?,
        status: TaskStatus::from_str(&status_str).unwrap_or_default(),
        category: row.get(4)?,
        sort_order: row.get(5)?,
        is_passed: is_passed_str == "true",
        created_at: chrono::DateTime::parse_from_rfc3339(&created_at_str)
            .map(|dt| dt.with_timezone(&Utc))
            .unwrap_or_else(|_| Utc::now()),
        updated_at: chrono::DateTime::parse_from_rfc3339(&updated_at_str)
            .map(|dt| dt.with_timezone(&Utc))
            .unwrap_or_else(|_| Utc::now()),
    })
}

pub(crate) fn encode_cursor(id: &str) -> String {
    use std::io::Write;
    let mut encoder = base64::write::EncoderStringWriter::new(&base64::engine::general_purpose::URL_SAFE_NO_PAD);
    encoder.write_all(id.as_bytes()).unwrap();
    encoder.into_inner()
}

fn decode_cursor(cursor: &str) -> DbResult<String> {
    use base64::Engine;
    let bytes = base64::engine::general_purpose::URL_SAFE_NO_PAD
        .decode(cursor)
        .map_err(|e| super::DbError::InvalidId(format!("Invalid cursor: {}", e)))?;
    String::from_utf8(bytes)
        .map_err(|e| super::DbError::InvalidId(format!("Invalid cursor UTF-8: {}", e)))
}

// =============================================================================
// TESTS
// =============================================================================

#[cfg(test)]
mod tests {
    use super::*;
    use crate::db::connection::open_in_memory;

    fn create_test_task(title: &str) -> ProjectTask {
        ProjectTask::new(title)
    }

    // -------------------------------------------------------------------------
    // Create tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_create_task() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task("Test task");

        create_task(&conn, &task).expect("Failed to create task");

        let retrieved = get_task(&conn, &task.id).expect("Failed to get task");
        assert!(retrieved.is_some());

        let retrieved = retrieved.unwrap();
        assert_eq!(retrieved.title, "Test task");
        assert_eq!(retrieved.status, TaskStatus::Backlog);
    }

    #[test]
    fn test_create_task_with_all_fields() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let task = create_test_task("Full task")
            .with_description("A description")
            .with_status(TaskStatus::Doing)
            .with_category("core")
            .with_sort_order(5.5);

        create_task(&conn, &task).expect("Failed to create task");

        let retrieved = get_task(&conn, &task.id).expect("Failed to get task").unwrap();
        assert_eq!(retrieved.description, Some("A description".to_string()));
        assert_eq!(retrieved.status, TaskStatus::Doing);
        assert_eq!(retrieved.category, Some("core".to_string()));
        assert_eq!(retrieved.sort_order, 5.5);
