//! Project progress CRUD operations.
//!
//! This module provides CRUD operations for project progress entries.
//! Progress entries are log messages within work sessions, using composite IDs.
//!
//! ## Composite ID Format
//!
//! `session#{session_ulid}#{progress_ulid}`
//!
//! This allows efficient prefix queries: `WHERE id GLOB 'session#<session_id>#*'`
//!
//! ## FTS5 Search
//!
//! Progress content is indexed in `project_progress_fts` for full-text search.

use chrono::Utc;
use rusqlite::{params, Connection, OptionalExtension};

use super::types::{PaginatedResult, ProjectProgress};
use super::DbResult;

// =============================================================================
// CREATE
// =============================================================================

/// Create a new progress entry (internal use).
pub fn create_progress(conn: &Connection, progress: &ProjectProgress) -> DbResult<()> {
    conn.execute(
        r#"
        INSERT INTO project_progress (id, content, created_at)
        VALUES (?1, ?2, ?3)
        "#,
        params![
            progress.id,
            progress.content,
            progress.created_at.to_rfc3339(),
        ],
    )?;
    Ok(())
}

/// Add a progress entry to a session.
///
/// Generates the progress ID automatically.
pub fn add_progress(conn: &Connection, session_id: &str, content: &str) -> DbResult<ProjectProgress> {
    let progress = ProjectProgress::new(session_id, content)?;
    create_progress(conn, &progress)?;
    Ok(progress)
}

// =============================================================================
// READ
// =============================================================================

/// Get a progress entry by ID.
pub fn get_progress(conn: &Connection, id: &str) -> DbResult<Option<ProjectProgress>> {
    let result = conn
        .query_row(
            r#"
            SELECT id, content, created_at
            FROM project_progress
            WHERE id = ?1
            "#,
            [id],
            |row| row_to_progress(row),
        )
        .optional()?;
    Ok(result)
}

/// List all progress entries for a session.
///
/// Returns entries ordered by creation time (ULID order).
pub fn list_progress_for_session(conn: &Connection, session_id: &str) -> DbResult<Vec<ProjectProgress>> {
    let pattern = ProjectProgress::glob_pattern(session_id);

    let mut stmt = conn.prepare(
        r#"
        SELECT id, content, created_at
        FROM project_progress
        WHERE id GLOB ?1
        ORDER BY id ASC
        "#,
    )?;

    let rows = stmt.query_map([pattern], |row| row_to_progress(row))?;

    let mut entries = Vec::new();
    for row in rows {
        entries.push(row?);
    }

    Ok(entries)
}

/// List all progress entries with pagination.
///
/// Returns entries ordered by creation time (most recent first).
pub fn list_progress(
    conn: &Connection,
    cursor: Option<&str>,
    limit: Option<usize>,
) -> DbResult<PaginatedResult<ProjectProgress>> {
    let limit = limit.unwrap_or(super::tasks::DEFAULT_PAGE_SIZE);

    let after_id = cursor
        .map(|c| super::tasks::decode_cursor(c))
        .transpose()?;

    let mut entries = Vec::new();

    if let Some(after_id) = after_id {
        // Get the created_at of the cursor entry
        let cursor_created: Option<String> = conn
            .query_row(
                "SELECT created_at FROM project_progress WHERE id = ?1",
                [&after_id],
                |row| row.get(0),
            )
            .optional()?;

        if let Some(created) = cursor_created {
            let mut stmt = conn.prepare(
                r#"
                SELECT id, content, created_at
                FROM project_progress
                WHERE (created_at < ?1) OR (created_at = ?1 AND id < ?2)
                ORDER BY created_at DESC, id DESC
                LIMIT ?3
                "#,
            )?;

            let rows = stmt.query_map(params![created, after_id, (limit + 1) as i64], |row| {
                row_to_progress(row)
            })?;
            for row in rows {
                entries.push(row?);
            }
        }
    } else {
        let mut stmt = conn.prepare(
            r#"
            SELECT id, content, created_at
            FROM project_progress
            ORDER BY created_at DESC, id DESC
            LIMIT ?1
            "#,
        )?;

        let rows = stmt.query_map([(limit + 1) as i64], |row| row_to_progress(row))?;
        for row in rows {
            entries.push(row?);
        }
    }

    let has_next = entries.len() > limit;
    if has_next {
        entries.pop();
    }

    let has_prev = cursor.is_some();

    let next_cursor = if has_next {
        entries.last().map(|p| super::tasks::encode_cursor(&p.id))
    } else {
        None
    };

    let prev_cursor = if has_prev {
        entries.first().map(|p| super::tasks::encode_cursor(&p.id))
    } else {
        None
    };

    Ok(PaginatedResult::new(
        entries,
        has_next,
        has_prev,
        next_cursor,
        prev_cursor,
    ))
}

/// Search progress entries using full-text search.
pub fn search_progress(
    conn: &Connection,
    query: &str,
    limit: Option<usize>,
) -> DbResult<Vec<ProjectProgress>> {
    let limit = limit.unwrap_or(super::tasks::DEFAULT_PAGE_SIZE);

    let mut stmt = conn.prepare(
        r#"
        SELECT p.id, p.content, p.created_at
        FROM project_progress p
        JOIN project_progress_fts fts ON p.rowid = fts.rowid
        WHERE project_progress_fts MATCH ?1
        ORDER BY rank
        LIMIT ?2
        "#,
    )?;

    let rows = stmt.query_map(params![query, limit as i64], |row| row_to_progress(row))?;

    let mut entries = Vec::new();
    for row in rows {
        entries.push(row?);
    }

    Ok(entries)
}

/// Count total progress entries.
pub fn count_progress(conn: &Connection) -> DbResult<i64> {
    let count: i64 = conn.query_row("SELECT COUNT(*) FROM project_progress", [], |row| row.get(0))?;
    Ok(count)
}

/// Count progress entries for a session.
pub fn count_progress_for_session(conn: &Connection, session_id: &str) -> DbResult<i64> {
    let pattern = ProjectProgress::glob_pattern(session_id);
    let count: i64 = conn.query_row(
        "SELECT COUNT(*) FROM project_progress WHERE id GLOB ?1",
        [pattern],
        |row| row.get(0),
    )?;
    Ok(count)
}

// =============================================================================
// UPDATE
// =============================================================================

/// Update progress content.
pub fn update_progress_content(conn: &Connection, id: &str, content: &str) -> DbResult<bool> {
    let rows_affected = conn.execute(
        "UPDATE project_progress SET content = ?1 WHERE id = ?2",
        params![content, id],
    )?;
    Ok(rows_affected > 0)
}

// =============================================================================
// DELETE
// =============================================================================

/// Delete a progress entry by ID.
pub fn delete_progress(conn: &Connection, id: &str) -> DbResult<bool> {
    let rows_affected = conn.execute("DELETE FROM project_progress WHERE id = ?1", [id])?;
    Ok(rows_affected > 0)
}

/// Delete all progress entries for a session.
pub fn delete_progress_for_session(conn: &Connection, session_id: &str) -> DbResult<i64> {
    let pattern = ProjectProgress::glob_pattern(session_id);
    let rows_affected = conn.execute("DELETE FROM project_progress WHERE id GLOB ?1", [pattern])?;
    Ok(rows_affected as i64)
}

// =============================================================================
// HELPERS
// =============================================================================

fn row_to_progress(row: &rusqlite::Row) -> rusqlite::Result<ProjectProgress> {
    let created_at_str: String = row.get(2)?;

    Ok(ProjectProgress {
        id: row.get(0)?,
        content: row.get(1)?,
        created_at: chrono::DateTime::parse_from_rfc3339(&created_at_str)
            .map(|dt| dt.with_timezone(&Utc))
            .unwrap_or_else(|_| Utc::now()),
    })
}

// =============================================================================
// TESTS
// =============================================================================

#[cfg(test)]
mod tests {
    use super::*;
    use crate::db::connection::open_in_memory;
    use crate::db::sessions::start_session;

    fn create_test_session(conn: &Connection) -> crate::db::types::WorkSession {
        start_session(conn, None).expect("Failed to start session")
    }

    // -------------------------------------------------------------------------
    // Create tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_add_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        let progress = add_progress(&conn, &session.id, "Did something").expect("Failed to add progress");

        assert!(progress.id.starts_with(&format!("session#{}#", session.id)));
        assert_eq!(progress.content, "Did something");
    }

    #[test]
    fn test_add_multiple_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        add_progress(&conn, &session.id, "Entry 1").expect("Add progress");
        add_progress(&conn, &session.id, "Entry 2").expect("Add progress");
        add_progress(&conn, &session.id, "Entry 3").expect("Add progress");

        let entries = list_progress_for_session(&conn, &session.id).expect("List progress");
        assert_eq!(entries.len(), 3);
    }

    // -------------------------------------------------------------------------
    // Read tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_get_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        let progress = add_progress(&conn, &session.id, "My entry").expect("Add progress");
        let retrieved = get_progress(&conn, &progress.id).expect("Get progress").unwrap();

        assert_eq!(retrieved.id, progress.id);
        assert_eq!(retrieved.content, "My entry");
    }

    #[test]
    fn test_get_progress_not_found() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let result = get_progress(&conn, "session#01ARZ3NDEKTSV4RRFFQ69G5FAV#01BSZ3NDEKTSV4RRFFQ69G5FBV")
            .expect("Query failed");
        assert!(result.is_none());
    }

    #[test]
    fn test_list_progress_for_session_empty() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        let entries = list_progress_for_session(&conn, &session.id).expect("List progress");
        assert!(entries.is_empty());
    }

    #[test]
    fn test_list_progress_for_session_ordered() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        let p1 = add_progress(&conn, &session.id, "First").expect("Add progress");
        std::thread::sleep(std::time::Duration::from_millis(2));
        let p2 = add_progress(&conn, &session.id, "Second").expect("Add progress");
        std::thread::sleep(std::time::Duration::from_millis(2));
        let p3 = add_progress(&conn, &session.id, "Third").expect("Add progress");

        let entries = list_progress_for_session(&conn, &session.id).expect("List progress");

        assert_eq!(entries.len(), 3);
        assert_eq!(entries[0].id, p1.id);
        assert_eq!(entries[1].id, p2.id);
        assert_eq!(entries[2].id, p3.id);
    }

    #[test]
    fn test_list_progress_for_session_only_for_session() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session1 = create_test_session(&conn);
        let session2 = create_test_session(&conn);

        add_progress(&conn, &session1.id, "S1 Entry 1").expect("Add progress");
        add_progress(&conn, &session1.id, "S1 Entry 2").expect("Add progress");
        add_progress(&conn, &session2.id, "S2 Entry 1").expect("Add progress");

        let s1_entries = list_progress_for_session(&conn, &session1.id).expect("List progress");
        let s2_entries = list_progress_for_session(&conn, &session2.id).expect("List progress");

        assert_eq!(s1_entries.len(), 2);
        assert_eq!(s2_entries.len(), 1);
    }

    #[test]
    fn test_list_progress_empty() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let result = list_progress(&conn, None, None).expect("List progress");

        assert!(result.items.is_empty());
        assert!(!result.has_next);
        assert!(!result.has_prev);
    }

    #[test]
    fn test_search_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        add_progress(&conn, &session.id, "Implemented authentication feature").expect("Add progress");
        add_progress(&conn, &session.id, "Fixed critical bug in login").expect("Add progress");
        add_progress(&conn, &session.id, "Updated documentation").expect("Add progress");

        // Search for "bug"
        let results = search_progress(&conn, "bug", None).expect("Search failed");
        assert_eq!(results.len(), 1);
        assert!(results[0].content.contains("bug"));

        // Search for "feature"
        let results = search_progress(&conn, "feature", None).expect("Search failed");
        assert_eq!(results.len(), 1);
        assert!(results[0].content.contains("feature"));
    }

    #[test]
    fn test_count_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        add_progress(&conn, &session.id, "Entry 1").expect("Add progress");
        add_progress(&conn, &session.id, "Entry 2").expect("Add progress");

        let count = count_progress(&conn).expect("Count progress");
        assert_eq!(count, 2);
    }

    #[test]
    fn test_count_progress_for_session() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session1 = create_test_session(&conn);
        let session2 = create_test_session(&conn);

        add_progress(&conn, &session1.id, "Entry 1").expect("Add progress");
        add_progress(&conn, &session1.id, "Entry 2").expect("Add progress");
        add_progress(&conn, &session2.id, "Entry 1").expect("Add progress");

        let s1_count = count_progress_for_session(&conn, &session1.id).expect("Count");
        let s2_count = count_progress_for_session(&conn, &session2.id).expect("Count");

        assert_eq!(s1_count, 2);
        assert_eq!(s2_count, 1);
    }

    // -------------------------------------------------------------------------
    // Update tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_update_progress_content() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        let progress = add_progress(&conn, &session.id, "Original").expect("Add progress");
        update_progress_content(&conn, &progress.id, "Updated").expect("Update progress");

        let retrieved = get_progress(&conn, &progress.id).expect("Get progress").unwrap();
        assert_eq!(retrieved.content, "Updated");
    }

    // -------------------------------------------------------------------------
    // Delete tests
    // -------------------------------------------------------------------------

    #[test]
    fn test_delete_progress() {
        let conn = open_in_memory().expect("Failed to open in-memory db");
        let session = create_test_session(&conn);

        let progress = add_progress(&conn, &session.id, "Entry").expect("Add progress");
