mod db;
mod pty;

#[cfg(debug_assertions)]
mod dev_bridge;

use pty::PtyManager;
use std::sync::Arc;

#[tauri::command]
fn greet(name: &str) -> String {
    format!("Hello, {}! You've been greeted from Rust!", name)
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    let pty_manager = Arc::new(PtyManager::new());

    // Start dev bridge in debug mode
