   683→
   684→            match format {
   685→                OutputFormat::Json => {
   686→                    if let Some(task) = db::get_task(&conn, &id)? {
   687→                        println!("{}", serde_json::to_string(&task).unwrap_or_default());
   688→                    }
   689→                }
