   712→                OutputFormat::Quiet => {
   713→                    println!("{}", id);
   714→                }
   715→                OutputFormat::Text => {
   716→                    println!("Deleted task: {}", id);
   717→                }
   718→            }
   719→        }
   720→
   721→        TaskCommands::Reorder { id, after } => {
   722→            let new_order = db::get_order_after(&conn, &after)?;
   723→            let mut update = db::TaskUpdate::default();
   724→            update.sort_order = Some(new_order);
