//! Harness CLI - Database utility for AI agents and humans.
//!
//! This CLI provides programmatic access to the Harness storage layer,
//! enabling AI agents to manage tasks, progress, and sessions.
//!
//! ## Usage
//!
//! ```bash
//! harness init                              # Create .harness/harness.db
//! harness db status                         # Show DB info
//! harness task add "Title" [-d "desc"]      # Add a task
//! harness task list [--status=TODO]         # List tasks
//! harness session start                     # Start work session
//! ```

use clap::{Parser, Subcommand, ValueEnum};
use hq_lib::db;
use std::path::PathBuf;
use std::process::ExitCode;

// =============================================================================
// CLI STRUCTURE
// =============================================================================

#[derive(Parser)]
#[command(name = "harness")]
#[command(author, version, about = "Harness CLI - Database utility for AI agents")]
#[command(propagate_version = true)]
struct Cli {
    /// Output format
    #[arg(long, value_enum, global = true, default_value = "text")]
    format: OutputFormat,

    /// Project directory (defaults to current directory)
    #[arg(short = 'C', long, global = true)]
    dir: Option<PathBuf>,

    #[command(subcommand)]
    command: Commands,
}

#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
enum OutputFormat {
    /// Human-readable text
    Text,
    /// JSON for programmatic use
    Json,
    /// IDs only (one per line)
    Quiet,
}

#[derive(Subcommand)]
enum Commands {
    /// Initialize a new Harness project
    Init,

    /// Database operations
    Db {
        #[command(subcommand)]
        command: DbCommands,
    },

    /// Task management
    Task {
        #[command(subcommand)]
        command: TaskCommands,
    },

    /// Task step management
    Step {
        #[command(subcommand)]
        command: StepCommands,
    },

    /// Work session management
    Session {
        #[command(subcommand)]
        command: SessionCommands,
    },

    /// Progress log management
    Progress {
        #[command(subcommand)]
        command: ProgressCommands,
    },

    /// Show project status summary
    Status,
}

// -----------------------------------------------------------------------------
// DB Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum DbCommands {
    /// Show database status and statistics
    Status,
}

// -----------------------------------------------------------------------------
// Task Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum TaskCommands {
    /// Add a new task
    Add {
        /// Task title
        title: String,

        /// Task description
        #[arg(short, long)]
        description: Option<String>,

        /// Task category
        #[arg(short, long)]
        category: Option<String>,

        /// Initial status
        #[arg(short, long, value_enum, default_value = "backlog")]
        status: TaskStatusArg,
    },

    /// List tasks
    List {
        /// Filter by status
        #[arg(short, long, value_enum)]
        status: Option<TaskStatusArg>,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,

        /// Pagination cursor
        #[arg(long)]
        cursor: Option<String>,
    },

    /// Search tasks using full-text search
    Search {
        /// Search query
        query: String,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },

    /// Get a task by ID
    Get {
        /// Task ID (ULID)
        id: String,
    },

    /// Update a task
    Update {
        /// Task ID (ULID)
        id: String,

        /// New title
        #[arg(short, long)]
        title: Option<String>,

        /// New description
        #[arg(short, long)]
        description: Option<String>,

        /// New category
        #[arg(short, long)]
        category: Option<String>,

        /// New status
        #[arg(long, value_enum)]
        status: Option<TaskStatusArg>,

        /// Mark as passed (true/false)
        #[arg(long)]
        passed: Option<bool>,
    },

    /// Delete a task
    Delete {
        /// Task ID (ULID)
        id: String,
    },

    /// Reorder a task
    Reorder {
        /// Task ID to move
        id: String,

        /// Place after this task ID
        #[arg(long)]
        after: String,
    },
}

#[derive(Copy, Clone, PartialEq, Eq, ValueEnum)]
enum TaskStatusArg {
    Backlog,
    Todo,
    Doing,
    Review,
    Qa,
    Done,
}

impl From<TaskStatusArg> for db::TaskStatus {
    fn from(arg: TaskStatusArg) -> Self {
        match arg {
            TaskStatusArg::Backlog => db::TaskStatus::Backlog,
            TaskStatusArg::Todo => db::TaskStatus::Todo,
            TaskStatusArg::Doing => db::TaskStatus::Doing,
            TaskStatusArg::Review => db::TaskStatus::Review,
            TaskStatusArg::Qa => db::TaskStatus::Qa,
            TaskStatusArg::Done => db::TaskStatus::Done,
        }
    }
}

// -----------------------------------------------------------------------------
// Step Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum StepCommands {
    /// Add a step to a task
    Add {
        /// Parent task ID
        task_id: String,

        /// Step description
        description: String,
    },

    /// List steps for a task
    List {
        /// Parent task ID
        task_id: String,
    },

    /// Mark a step as complete
    Complete {
        /// Step ID
        id: String,
    },

    /// Mark a step as incomplete
    Uncomplete {
        /// Step ID
        id: String,
    },

    /// Toggle step completion
    Toggle {
        /// Step ID
        id: String,
    },

    /// Delete a step
    Delete {
        /// Step ID
        id: String,
    },
}

// -----------------------------------------------------------------------------
// Session Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum SessionCommands {
    /// Start a new work session
    Start {
        /// Session summary
        #[arg(short, long)]
        summary: Option<String>,
    },

    /// End the current session
    End {
        /// Final summary
        #[arg(short, long)]
        summary: Option<String>,
    },

    /// Show current active session
    Current,

    /// List sessions
    List {
        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,

        /// Pagination cursor
        #[arg(long)]
        cursor: Option<String>,
    },

    /// Get a session by ID
    Get {
        /// Session ID (ULID)
        id: String,
    },
}

// -----------------------------------------------------------------------------
// Progress Subcommands
// -----------------------------------------------------------------------------

#[derive(Subcommand)]
enum ProgressCommands {
    /// Add a progress entry
    Add {
        /// Progress content
        content: String,

        /// Session ID (uses current session if not specified)
        #[arg(short, long)]
        session: Option<String>,
    },

    /// List progress entries
    List {
        /// Filter by session ID
        #[arg(short, long)]
        session: Option<String>,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,

        /// Pagination cursor
        #[arg(long)]
        cursor: Option<String>,
    },

    /// Search progress using full-text search
    Search {
        /// Search query
        query: String,

        /// Maximum number of results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },
}

// =============================================================================
// MAIN
// =============================================================================

fn main() -> ExitCode {
    let cli = Cli::parse();

    // Determine project directory
    let project_dir = cli.dir.unwrap_or_else(|| std::env::current_dir().unwrap_or_default());

    let result = match cli.command {
        Commands::Init => cmd_init(&project_dir, cli.format),
        Commands::Db { command } => match command {
            DbCommands::Status => cmd_db_status(&project_dir, cli.format),
        },
        Commands::Task { command } => cmd_task(&project_dir, command, cli.format),
        Commands::Step { command } => cmd_step(&project_dir, command, cli.format),
        Commands::Session { command } => cmd_session(&project_dir, command, cli.format),
        Commands::Progress { command } => cmd_progress(&project_dir, command, cli.format),
        Commands::Status => cmd_status(&project_dir, cli.format),
    };

    match result {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("Error: {}", e);
            match e {
                CliError::NotHarnessProject => ExitCode::from(2),
                CliError::Database(_) => ExitCode::from(3),
                _ => ExitCode::FAILURE,
            }
        }
    }
}

// =============================================================================
// ERROR HANDLING
// =============================================================================

#[derive(Debug)]
enum CliError {
    NotHarnessProject,
    Database(db::DbError),
    NotFound(String),
    NoActiveSession,
    Io(std::io::Error),
}

impl std::fmt::Display for CliError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            CliError::NotHarnessProject => write!(f, "Not a Harness project (no .harness/ folder)"),
            CliError::Database(e) => write!(f, "Database error: {}", e),
            CliError::NotFound(what) => write!(f, "Not found: {}", what),
            CliError::NoActiveSession => write!(f, "No active session"),
            CliError::Io(e) => write!(f, "IO error: {}", e),
        }
    }
}

impl From<db::DbError> for CliError {
    fn from(e: db::DbError) -> Self {
        CliError::Database(e)
    }
}

impl From<std::io::Error> for CliError {
    fn from(e: std::io::Error) -> Self {
        CliError::Io(e)
    }
}

type CliResult<T> = Result<T, CliError>;

// =============================================================================
// COMMAND IMPLEMENTATIONS
// =============================================================================

fn cmd_init(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
    let harness_dir = project_dir.join(db::HARNESS_FOLDER);

    // Create .harness/ if it doesn't exist
    if !harness_dir.exists() {
        std::fs::create_dir_all(&harness_dir)?;
    }

    // Open or create the database
    let conn = db::open_or_create(project_dir)?;

    let db_path = db::get_db_path(project_dir);

    match format {
        OutputFormat::Json => {
            println!(
                r#"{{"success":true,"path":"{}","version":"{}"}}"#,
                db_path.display(),
                db::SCHEMA_VERSION
            );
        }
        OutputFormat::Quiet => {
            println!("{}", db_path.display());
        }
        OutputFormat::Text => {
            println!("Initialized Harness database at {}", db_path.display());
            println!("Schema version: {}", db::SCHEMA_VERSION);

            // Show stats
            let stats = db::DbStats::collect(&conn, Some(&db_path))?;
            println!("\nDatabase stats:");
            println!("  Tasks:    {}", stats.task_count);
            println!("  Steps:    {}", stats.step_count);
            println!("  Sessions: {}", stats.session_count);
            println!("  Progress: {}", stats.progress_count);
        }
    }

    Ok(())
}

fn cmd_db_status(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;
    let db_path = db::get_db_path(project_dir);
    let stats = db::DbStats::collect(&conn, Some(&db_path))?;
    let version = db::get_schema_version(&conn)?.unwrap_or_else(|| "unknown".to_string());

    match format {
        OutputFormat::Json => {
            println!(
                r#"{{"path":"{}","version":"{}","size_bytes":{},"tasks":{},"steps":{},"sessions":{},"progress":{}}}"#,
                db_path.display(),
                version,
                stats.file_size_bytes,
                stats.task_count,
                stats.step_count,
                stats.session_count,
                stats.progress_count
            );
        }
        OutputFormat::Quiet => {
            println!("{}", db_path.display());
        }
        OutputFormat::Text => {
            println!("Database: {}", db_path.display());
            println!("Schema version: {}", version);
            println!("Size: {} bytes", stats.file_size_bytes);
            println!();
            println!("Counts:");
            println!("  Tasks:    {}", stats.task_count);
            println!("  Steps:    {}", stats.step_count);
            println!("  Sessions: {}", stats.session_count);
            println!("  Progress: {}", stats.progress_count);
        }
    }

    Ok(())
}

fn cmd_task(project_dir: &PathBuf, command: TaskCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        TaskCommands::Add {
            title,
            description,
            category,
            status,
        } => {
            let mut task = db::ProjectTask::new(&title).with_status(status.into());

            if let Some(ref desc) = description {
                task = task.with_description(desc);
            }
            if let Some(ref cat) = category {
                task = task.with_category(cat);
            }

            db::create_task(&conn, &task)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&task).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", task.id);
                }
                OutputFormat::Text => {
                    println!("Created task: {}", task.id);
                    println!("  Title:  {}", task.title);
                    println!("  Status: {}", task.status.as_str());
                }
            }
        }

        TaskCommands::List { status, limit, cursor } => {
            let result = if let Some(status) = status {
                db::list_tasks_by_status(&conn, status.into(), cursor.as_deref(), Some(limit))?
            } else {
                db::list_tasks(&conn, cursor.as_deref(), Some(limit))?
            };

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&result).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for task in &result.items {
                        println!("{}", task.id);
                    }
                }
                OutputFormat::Text => {
                    if result.items.is_empty() {
                        println!("No tasks found.");
                    } else {
                        println!("{:<26}  {:<8}  {}", "ID", "STATUS", "TITLE");
                        println!("{}", "-".repeat(70));
                        for task in &result.items {
                            println!(
                                "{:<26}  {:<8}  {}",
                                task.id,
                                task.status.as_str(),
                                truncate(&task.title, 32)
                            );
                        }
                        if result.has_next {
                            println!();
                            println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                        }
                    }
                }
            }
        }

        TaskCommands::Search { query, limit } => {
            let tasks = db::search_tasks(&conn, &query, Some(limit))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&tasks).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for task in &tasks {
                        println!("{}", task.id);
                    }
                }
                OutputFormat::Text => {
                    if tasks.is_empty() {
                        println!("No tasks found matching '{}'.", query);
                    } else {
                        println!("Found {} task(s) matching '{}':", tasks.len(), query);
                        println!();
                        println!("{:<26}  {:<8}  {}", "ID", "STATUS", "TITLE");
                        println!("{}", "-".repeat(70));
                        for task in &tasks {
                            println!(
                                "{:<26}  {:<8}  {}",
                                task.id,
                                task.status.as_str(),
                                truncate(&task.title, 32)
                            );
                        }
                    }
                }
            }
        }

        TaskCommands::Get { id } => {
            let task = db::get_task(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Task {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&task).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", task.id);
                }
                OutputFormat::Text => {
                    println!("ID:          {}", task.id);
                    println!("Title:       {}", task.title);
                    println!("Status:      {}", task.status.as_str());
                    println!("Category:    {}", task.category.as_deref().unwrap_or("-"));
                    println!("Description: {}", task.description.as_deref().unwrap_or("-"));
                    println!("Passed:      {}", task.is_passed);
                    println!("Order:       {:.2}", task.sort_order);
                    println!("Created:     {}", task.created_at);
                    println!("Updated:     {}", task.updated_at);

                    // Show steps
                    let steps = db::list_steps(&conn, &id)?;
                    if !steps.is_empty() {
                        println!();
                        println!("Steps ({}):", steps.len());
                        for step in &steps {
                            let check = if step.is_completed { "[x]" } else { "[ ]" };
                            println!("  {} {}", check, step.description);
                        }
                    }
                }
            }
        }

        TaskCommands::Update {
            id,
            title,
            description,
            category,
            status,
            passed,
        } => {
            let mut update = db::TaskUpdate::default();
            update.title = title;
            update.description = description;
            update.category = category;
            update.status = status.map(|s| s.into());

            let updated = db::update_task(&conn, &id, &update)?;

            if let Some(p) = passed {
                db::set_task_passed(&conn, &id, p)?;
            }

            if !updated && passed.is_none() {
                return Err(CliError::NotFound(format!("Task {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    if let Some(task) = db::get_task(&conn, &id)? {
                        println!("{}", serde_json::to_string(&task).unwrap_or_default());
                    }
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Updated task: {}", id);
                }
            }
        }

        TaskCommands::Delete { id } => {
            // Delete steps first
            db::delete_steps_for_task(&conn, &id)?;

            let deleted = db::delete_task(&conn, &id)?;
            if !deleted {
                return Err(CliError::NotFound(format!("Task {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"deleted":true,"id":"{}"}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Deleted task: {}", id);
                }
            }
        }

        TaskCommands::Reorder { id, after } => {
            let new_order = db::get_order_after(&conn, &after)?;
            let mut update = db::TaskUpdate::default();
            update.sort_order = Some(new_order);

            let updated = db::update_task(&conn, &id, &update)?;
            if !updated {
                return Err(CliError::NotFound(format!("Task {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","sort_order":{}}}"#, id, new_order);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Reordered task {} after {}", id, after);
                }
            }
        }
    }

    Ok(())
}

fn cmd_step(project_dir: &PathBuf, command: StepCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        StepCommands::Add { task_id, description } => {
            let step = db::add_step(&conn, &task_id, &description)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&step).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", step.id);
                }
                OutputFormat::Text => {
                    println!("Added step: {}", step.id);
                    println!("  Task:        {}", task_id);
                    println!("  Description: {}", step.description);
                }
            }
        }

        StepCommands::List { task_id } => {
            let steps = db::list_steps(&conn, &task_id)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&steps).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for step in &steps {
                        println!("{}", step.id);
                    }
                }
                OutputFormat::Text => {
                    if steps.is_empty() {
                        println!("No steps for task {}.", task_id);
                    } else {
                        println!("Steps for task {} ({}):", task_id, steps.len());
                        println!();
                        for step in &steps {
                            let check = if step.is_completed { "[x]" } else { "[ ]" };
                            println!("{} {} - {}", check, step.id, step.description);
                        }
                    }
                }
            }
        }

        StepCommands::Complete { id } => {
            let completed = db::complete_step(&conn, &id)?;
            if !completed {
                return Err(CliError::NotFound(format!("Step {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","is_completed":true}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Completed step: {}", id);
                }
            }
        }

        StepCommands::Uncomplete { id } => {
            let uncompleted = db::uncomplete_step(&conn, &id)?;
            if !uncompleted {
                return Err(CliError::NotFound(format!("Step {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","is_completed":false}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Uncompleted step: {}", id);
                }
            }
        }

        StepCommands::Toggle { id } => {
            let new_state = db::toggle_step(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Step {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"id":"{}","is_completed":{}}}"#, id, new_state);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    let state = if new_state { "completed" } else { "incomplete" };
                    println!("Step {} is now {}", id, state);
                }
            }
        }

        StepCommands::Delete { id } => {
            let deleted = db::delete_step(&conn, &id)?;
            if !deleted {
                return Err(CliError::NotFound(format!("Step {}", id)));
            }

            match format {
                OutputFormat::Json => {
                    println!(r#"{{"deleted":true,"id":"{}"}}"#, id);
                }
                OutputFormat::Quiet => {
                    println!("{}", id);
                }
                OutputFormat::Text => {
                    println!("Deleted step: {}", id);
                }
            }
        }
    }

    Ok(())
}

fn cmd_session(project_dir: &PathBuf, command: SessionCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        SessionCommands::Start { summary } => {
            let session = db::start_session(&conn, summary.as_deref())?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("Started session: {}", session.id);
                    if let Some(s) = &session.summary {
                        println!("  Summary: {}", s);
                    }
                    println!("  Started: {}", session.started_at);
                }
            }
        }

        SessionCommands::End { summary } => {
            let session_id = db::end_current_session(&conn, summary.as_deref())?
                .ok_or(CliError::NoActiveSession)?;

            match format {
                OutputFormat::Json => {
                    if let Some(session) = db::get_session(&conn, &session_id)? {
                        println!("{}", serde_json::to_string(&session).unwrap_or_default());
                    }
                }
                OutputFormat::Quiet => {
                    println!("{}", session_id);
                }
                OutputFormat::Text => {
                    println!("Ended session: {}", session_id);
                }
            }
        }

        SessionCommands::Current => {
            let session = db::get_current_session(&conn)?
                .ok_or(CliError::NoActiveSession)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("Current session: {}", session.id);
                    if let Some(s) = &session.summary {
                        println!("  Summary: {}", s);
                    }
                    println!("  Started: {}", session.started_at);

                    // Show progress count
                    let count = db::count_progress_for_session(&conn, &session.id)?;
                    println!("  Progress entries: {}", count);
                }
            }
        }

        SessionCommands::List { limit, cursor } => {
            let result = db::list_sessions(&conn, cursor.as_deref(), Some(limit))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&result).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for session in &result.items {
                        println!("{}", session.id);
                    }
                }
                OutputFormat::Text => {
                    if result.items.is_empty() {
                        println!("No sessions found.");
                    } else {
                        println!("{:<26}  {:<20}  {}", "ID", "STARTED", "STATUS");
                        println!("{}", "-".repeat(60));
                        for session in &result.items {
                            let status = if session.ended_at.is_some() { "ended" } else { "active" };
                            println!(
                                "{:<26}  {:<20}  {}",
                                session.id,
                                truncate(&session.started_at.to_string(), 20),
                                status
                            );
                        }
                        if result.has_next {
                            println!();
                            println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                        }
                    }
                }
            }
        }

        SessionCommands::Get { id } => {
            let session = db::get_session(&conn, &id)?
                .ok_or_else(|| CliError::NotFound(format!("Session {}", id)))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&session).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", session.id);
                }
                OutputFormat::Text => {
                    println!("ID:      {}", session.id);
                    println!("Summary: {}", session.summary.as_deref().unwrap_or("-"));
                    println!("Started: {}", session.started_at);
                    println!("Ended:   {}", session.ended_at.map(|d| d.to_string()).unwrap_or_else(|| "-".to_string()));

                    // Show progress entries
                    let progress = db::list_progress_for_session(&conn, &id)?;
                    if !progress.is_empty() {
                        println!();
                        println!("Progress ({}):", progress.len());
                        for entry in progress.iter().take(10) {
                            println!("  - {}", truncate(&entry.content, 60));
                        }
                        if progress.len() > 10 {
                            println!("  ... and {} more", progress.len() - 10);
                        }
                    }
                }
            }
        }
    }

    Ok(())
}

fn cmd_progress(project_dir: &PathBuf, command: ProgressCommands, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    match command {
        ProgressCommands::Add { content, session } => {
            // Use provided session or get current
            let session_id = match session {
                Some(id) => id,
                None => db::get_current_session(&conn)?
                    .ok_or(CliError::NoActiveSession)?
                    .id,
            };

            let progress = db::add_progress(&conn, &session_id, &content)?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&progress).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    println!("{}", progress.id);
                }
                OutputFormat::Text => {
                    println!("Added progress: {}", progress.id);
                    println!("  Session: {}", session_id);
                    println!("  Content: {}", truncate(&content, 60));
                }
            }
        }

        ProgressCommands::List { session, limit, cursor } => {
            if let Some(session_id) = session {
                // List for specific session
                let entries = db::list_progress_for_session(&conn, &session_id)?;

                match format {
                    OutputFormat::Json => {
                        println!("{}", serde_json::to_string(&entries).unwrap_or_default());
                    }
                    OutputFormat::Quiet => {
                        for entry in &entries {
                            println!("{}", entry.id);
                        }
                    }
                    OutputFormat::Text => {
                        if entries.is_empty() {
                            println!("No progress entries for session {}.", session_id);
                        } else {
                            println!("Progress for session {} ({}):", session_id, entries.len());
                            println!();
                            for entry in &entries {
                                println!("[{}] {}", entry.created_at.format("%H:%M:%S"), entry.content);
                            }
                        }
                    }
                }
            } else {
                // List all with pagination
                let result = db::list_progress(&conn, cursor.as_deref(), Some(limit))?;

                match format {
                    OutputFormat::Json => {
                        println!("{}", serde_json::to_string(&result).unwrap_or_default());
                    }
                    OutputFormat::Quiet => {
                        for entry in &result.items {
                            println!("{}", entry.id);
                        }
                    }
                    OutputFormat::Text => {
                        if result.items.is_empty() {
                            println!("No progress entries found.");
                        } else {
                            for entry in &result.items {
                                println!("[{}] {}", entry.created_at.format("%Y-%m-%d %H:%M"), entry.content);
                            }
                            if result.has_next {
                                println!();
                                println!("More results available. Use --cursor={}", result.next_cursor.as_deref().unwrap_or(""));
                            }
                        }
                    }
                }
            }
        }

        ProgressCommands::Search { query, limit } => {
            let entries = db::search_progress(&conn, &query, Some(limit))?;

            match format {
                OutputFormat::Json => {
                    println!("{}", serde_json::to_string(&entries).unwrap_or_default());
                }
                OutputFormat::Quiet => {
                    for entry in &entries {
                        println!("{}", entry.id);
                    }
                }
                OutputFormat::Text => {
                    if entries.is_empty() {
                        println!("No progress entries found matching '{}'.", query);
                    } else {
                        println!("Found {} entry(ies) matching '{}':", entries.len(), query);
                        println!();
                        for entry in &entries {
                            println!("[{}] {}", entry.created_at.format("%Y-%m-%d %H:%M"), entry.content);
                        }
                    }
                }
            }
        }
    }

    Ok(())
}

fn cmd_status(project_dir: &PathBuf, format: OutputFormat) -> CliResult<()> {
    if !db::has_harness_folder(project_dir) {
        return Err(CliError::NotHarnessProject);
    }

    let conn = db::open(project_dir)?;

    // Collect counts by status using the HashMap
    let status_counts = db::count_tasks_by_status(&conn)?;
    let backlog = status_counts.get("BACKLOG").copied().unwrap_or(0);
    let todo = status_counts.get("TODO").copied().unwrap_or(0);
    let doing = status_counts.get("DOING").copied().unwrap_or(0);
    let review = status_counts.get("REVIEW").copied().unwrap_or(0);
    let qa = status_counts.get("QA").copied().unwrap_or(0);
    let done = status_counts.get("DONE").copied().unwrap_or(0);
    let total = backlog + todo + doing + review + qa + done;

    let active_sessions = db::count_active_sessions(&conn)?;
    let total_sessions = db::count_sessions(&conn)?;
    let total_progress = db::count_progress(&conn)?;

    match format {
        OutputFormat::Json => {
            println!(
                r#"{{"tasks":{{"backlog":{},"todo":{},"doing":{},"review":{},"qa":{},"done":{},"total":{}}},"sessions":{{"active":{},"total":{}}},"progress":{}}}"#,
                backlog, todo, doing, review, qa, done, total,
                active_sessions, total_sessions,
                total_progress
            );
        }
        OutputFormat::Quiet => {
            println!("{}/{}", done, total);
        }
        OutputFormat::Text => {
            println!("Project Status");
            println!("==============");
            println!();
            println!("Tasks: {}/{} complete", done, total);
            println!();
            println!("  BACKLOG:  {}", backlog);
            println!("  TODO:     {}", todo);
            println!("  DOING:    {}", doing);
            println!("  REVIEW:   {}", review);
            println!("  QA:       {}", qa);
            println!("  DONE:     {}", done);
            println!();
            println!("Sessions: {} total ({} active)", total_sessions, active_sessions);
            println!("Progress entries: {}", total_progress);
        }
    }

    Ok(())
}

// =============================================================================
// HELPERS
// =============================================================================

fn truncate(s: &str, max_len: usize) -> String {
    if s.len() <= max_len {
        s.to_string()
    } else {
        format!("{}...", &s[..max_len.saturating_sub(3)])
    }
}

