        let conn = open_in_memory().expect("Failed to open in-memory db");

        // No current session initially
        let current = get_current_session(&conn).expect("Get current");
        assert!(current.is_none());

        // Start a session
        let session = start_session(&conn, None).expect("Start session");

        // Now there is a current session
        let current = get_current_session(&conn).expect("Get current").unwrap();
        assert_eq!(current.id, session.id);
    }

