    #[test]
    fn test_list_sessions_ordered_by_recent() {
        let conn = open_in_memory().expect("Failed to open in-memory db");

        let s1 = start_session(&conn, Some("First")).expect("Start session 1");
        std::thread::sleep(std::time::Duration::from_millis(2));
        let s2 = start_session(&conn, Some("Second")).expect("Start session 2");
        std::thread::sleep(std::time::Duration::from_millis(2));
        let s3 = start_session(&conn, Some("Third")).expect("Start session 3");

        let result = list_sessions(&conn, None, None).expect("List sessions");

        assert_eq!(result.items.len(), 3);
        // Most recent first
        assert_eq!(result.items[0].id, s3.id);
        assert_eq!(result.items[1].id, s2.id);
        assert_eq!(result.items[2].id, s1.id);
    }

